B.Xz=new A.l(2000,1,10,"\uc138\uae30\uc758 \ud569\ubcd1","AOL\uc774 \ud0c0\uc784\uc6cc\ub108\uc640 \ud569\ubcd1\uc744 \ubc1c\ud45c\ud588\ub2e4","\uc778\ud130\ub137 \uae30\uc5c5\uc774 \uc804\ud1b5 \ubbf8\ub514\uc5b4 \uacf5\ub8e1\uc744 \uc0bc\ud0a4\ub294 \uc0ac\uc0c1 \ucd5c\ub300 \uaddc\ubaa8\uc758 \ud569\ubcd1\uc774\ub2e4. \uc2e0\uacbd\uc81c\uc640 \uad6c\uacbd\uc81c\uc758 \uacb0\ud569\uc5d0 \uc2dc\uc7a5\uc774 \uc5f4\uad11\ud588\ub2e4.","\uac00\uc7a5 \ud070 \ubc15\uc218\ub97c \ubc1b\uc740 \ub51c\uc774 \ub298 \ucd5c\uace0\uc758 \ub51c\uc740 \uc544\ub2d9\ub2c8\ub2e4.",B.q)
B.Xr=new A.l(2000,1,14,"\uad6c\uacbd\uc81c \uc815\uc810","\ub2e4\uc6b0\uc9c0\uc218\uac00 \uc0ac\uc0c1 \ucd5c\uace0\ub85c \ub9c8\uac10\ud588\ub2e4","\ub2e4\uc6b0\uac00 11,722\ub97c \uae30\ub85d\ud558\uba70 \uc815\uc810\uc744 \ucc0d\uc5c8\ub2e4. \uc774 \uace0\uc810\uc740 \uc774\ud6c4 \uc5ec\ub7ec \ud574 \ub3d9\uc548 \ud68c\ubcf5\ub418\uc9c0 \ubabb\ud55c\ub2e4.","\uc9c0\uc218 \uc2e0\uace0\uac00\ub294 \ucd95\ud3ec\uc774\uc790, \ub4a4\ub97c \uc0b4\ud3b4\uc57c \ud55c\ub2e4\ub294 \uc2e0\ud638\uc774\uae30\ub3c4 \ud569\ub2c8\ub2e4.",B.q)
