B.XO=new A.l(2000,1,30,"\uc815\uce58 \uc9c0\ud615","\ubbfc\uc8fc\ub178\ub3d9\ub2f9\uc774 \ucc3d\ub2f9\ud588\ub2e4","\ub178\ub3d9\xb7\uc9c4\ubcf4 \uc9c4\uc601\uc774 \uc6d0\ub0b4 \uc9c4\ucd9c\uc744 \ubaa9\ud45c\ub85c \uc815\ub2f9\uc744 \uc138\uc6e0\ub2e4. \ud55c\uad6d \uc815\uce58 \uc9c0\ud615\uc758 \ub2e4\ubcc0\ud654\uac00 \uc2dc\uc791\ub410\ub2e4.","\uc815\ucc45 \uc9c0\ud615\uc758 \ubcc0\ud654\ub294 \uaddc\uc81c\uc640 \uc0b0\uc5c5\uc758 \ubc29\ud5a5\uc744 \ubc14\uafc9\ub2c8\ub2e4.",B.I)
