B.a_0=new A.l(2001,6,7,"\ub300\uaddc\ubaa8 \uac10\uc138","\ubd80\uc2dc, 1.35\uc870 \ub2ec\ub7ec \uac10\uc138\uc548 \uc11c\uba85","\ubbf8\uad6d\uc774 10\ub144\uc5d0 \uac78\uce5c \ub300\uaddc\ubaa8 \uac10\uc138\ub97c \ud655\uc815\ud588\ub2e4. \uac00\uacc4 \uc18c\ube44\uc640 \uc2dc\uc7a5 \uc720\ub3d9\uc131\uc5d0 \uc601\ud5a5\uc744 \uc900\ub2e4.","\uac10\uc138\ub294 \uc18c\ube44 \uc5ec\ub825\uc744 \ud0a4\uc6b0\uc9c0\ub9cc \ub098\ub77c \uacf3\uac04\uc740 \uc904\uc785\ub2c8\ub2e4.",B.q)
